import json
import urllib.parse
import requests
from requests.adapters import HTTPAdapter
from urllib3.util.retry import Retry

def lambda_handler(event, context):
    # Extract request from event
    request = event['Records'][0]['cf']['request']
    
    # Get headers
    headers = request['headers']
    
    # Check for enrichment URLs
    enrich_urls = headers.get('x-enrich-url', [])
    
    if not enrich_urls:
        return request
    
    # Prepare session with retries and timeout
    session = requests.Session()
    retry_strategy = Retry(
        total=3,
        backoff_factor=1,
        status_forcelist=[429, 500, 502, 503, 504],
    )
    adapter = HTTPAdapter(max_retries=retry_strategy)
    session.mount("http://", adapter)
    session.mount("https://", adapter)
    
    # Set timeout
    timeout = 5
    
    # Fetch data from URLs
    enrichment_data = {}
    
    for url_header in enrich_urls:
        url = url_header['value']
        
        # Validate URL format
        try:
            parsed_url = urllib.parse.urlparse(url)
            if not all([parsed_url.scheme, parsed_url.netloc]):
                continue
        except Exception:
            continue
            
        # Make request
        try:
            response = session.get(url, timeout=timeout)
            if response.status_code == 200:
                enrichment_data[url] = response.json()
        except Exception:
            # Continue with other URLs if one fails
            continue
    
    # Add enrichment data to request headers
    if enrichment_data:
        headers['x-enrich-data'] = [{'key': 'x-enrich-data', 'value': json.dumps(enrichment_data)}]
    
    return request